use App\Mail\OrderConfirmed;
use Illuminate\Support\Facades\Mail;

// In your OrderController or OrderService
Mail::to($order->user->email)->queue(new OrderConfirmed($order));

// Or dispatch with a delay
Mail::to($order->user->email)
    ->later(now()->addMinutes(5), new OrderConfirmed($order));

class OrderConfirmed extends Mailable implements ShouldQueue
{
    use Queueable, SerializesModels;

    // Retry up to 3 times
    public int $tries = 3;

    // Wait 60 seconds before retrying
    public int $backoff = 60;

    // Fail the job after 5 minutes total
    public int $timeout = 300;
}

public function failed(\Throwable $exception): void
{
    // Notify your team via Slack, log to Sentry, etc.
    \Log::critical('OrderConfirmed email failed permanently', [
        'order_id' => $this->order->id,
        'error' => $exception->getMessage(),
    ]);
}
